import axios from 'axios';

const API_URL = '/api/schemes';

// Get all schemes
const getSchemes = async (query = '') => {
  const response = await axios.get(`${API_URL}${query ? `?${query}` : ''}`);
  return response.data;
};

// Get scheme by ID
const getSchemeById = async (schemeId) => {
  const response = await axios.get(`${API_URL}/${schemeId}`);
  return response.data;
};

// Search schemes
const searchSchemes = async (searchTerm) => {
  const response = await axios.get(`${API_URL}/search?q=${searchTerm}`);
  return response.data;
};

// Get schemes by category
const getSchemesByCategory = async (category) => {
  const response = await axios.get(`${API_URL}/category/${category}`);
  return response.data;
};

// Bookmark a scheme
const bookmarkScheme = async (schemeId) => {
  const response = await axios.post(`${API_URL}/${schemeId}/bookmark`);
  return response.data;
};

// Remove bookmark
const removeBookmark = async (schemeId) => {
  const response = await axios.delete(`${API_URL}/${schemeId}/bookmark`);
  return response.data;
};

// Get user's bookmarked schemes
const getUserBookmarks = async () => {
  const response = await axios.get(`${API_URL}/bookmarks`);
  return response.data;
};

// Check if user has bookmarked a scheme
const checkBookmark = async (schemeId) => {
  const response = await axios.get(`${API_URL}/${schemeId}/bookmark`);
  return response.data;
};

// Apply for a scheme
const applyForScheme = async (schemeId, applicationData) => {
  const response = await axios.post(`${API_URL}/${schemeId}/apply`, applicationData);
  return response.data;
};

// Get user's applications
const getUserApplications = async () => {
  const response = await axios.get(`${API_URL}/applications`);
  return response.data;
};

// Get application status
const getApplicationStatus = async (applicationId) => {
  const response = await axios.get(`${API_URL}/applications/${applicationId}`);
  return response.data;
};

// Upload documents for application
const uploadDocuments = async (applicationId, formData) => {
  const response = await axios.post(`${API_URL}/applications/${applicationId}/documents`, formData, {
    headers: {
      'Content-Type': 'multipart/form-data'
    }
  });
  return response.data;
};

const schemeService = {
  getSchemes,
  getSchemeById,
  searchSchemes,
  getSchemesByCategory,
  bookmarkScheme,
  removeBookmark,
  getUserBookmarks,
  checkBookmark,
  applyForScheme,
  getUserApplications,
  getApplicationStatus,
  uploadDocuments
};

export default schemeService;
